INSERT INTO public.questions (id, quiz_id, question_text, options, correct_option_index, time_limit, type, correct_answer, matching_pairs) VALUES ('f10030cc-6928-4fb2-81e2-38f9e34807a8', '0fa26f27-81e5-4236-8bde-ad6dc243d4c9', 'INSTRUCCIÓN: Lee el siguiente párrafo y luego responde la pregunta:
"Asimismo les informo que el trabajo historico-crítico presentado anteayer por el joven rioplatense obtuvo el decimoprimer puesto".
La palabra compuesta que debe llevar tilde es:', '["Asimismo", "historico-crítico", "rioplatense", "decimoprimer"]'::jsonb, 1, 30, 'multiple_choice', NULL, NULL::jsonb);

INSERT INTO public.questions (id, quiz_id, question_text, options, correct_option_index, time_limit, type, correct_answer, matching_pairs) VALUES ('8273feb7-fcc4-4ed3-964e-4018ae8a8679', '0fa26f27-81e5-4236-8bde-ad6dc243d4c9', 'En el siguiente párrafo:
"Ella vio en ti lo mejor, mas creo que fue el quien te valoró mas".
¿Cuántos monosílabos deben llevar tilde?', '["uno", "tres", "cuatro", "dos"]'::jsonb, 3, 30, 'multiple_choice', NULL, NULL::jsonb);

INSERT INTO public.questions (id, quiz_id, question_text, options, correct_option_index, time_limit, type, correct_answer, matching_pairs) VALUES ('543aa850-78be-4052-9cb6-2c3e6a9be568', '0fa26f27-81e5-4236-8bde-ad6dc243d4c9', 'En el siguiente texto:
"A ti te di todo mi amor, mas ahora tu le niegas a mi corazón ese sentimiento".
¿Cuántos monosílabos deben llevar tilde?', '["uno", "dos", "tres", "cuatro"]'::jsonb, 0, 30, 'multiple_choice', NULL, NULL::jsonb);

INSERT INTO public.questions (id, quiz_id, question_text, options, correct_option_index, time_limit, type, correct_answer, matching_pairs) VALUES ('c2ee96af-0961-4eeb-b7ed-3049b84ef790', '0fa26f27-81e5-4236-8bde-ad6dc243d4c9', 'En cuál de las sgtes. oraciones, POR QUÉ / PORQUÉ deben llevar tilde:
II. ¿Por que lloras?
III. El porque no lo sé.', '["I", "III", "II, III", "en todas"]'::jsonb, 3, 30, 'multiple_choice', NULL, NULL::jsonb);

INSERT INTO public.questions (id, quiz_id, question_text, options, correct_option_index, time_limit, type, correct_answer, matching_pairs) VALUES ('9f82c21b-fd10-4add-a470-a30beebf80df', '5daafb27-da23-46e0-8eeb-ade5b2334b27', 'Coloque la tilde donde convenga y luego responda la pregunta:
"Sobre el ataud, colocare un clavel y rezare a la virgen con mucha devocion".
¿Cuántas oxítonas hay en total?', '["dos", "tres", "cuatro", "cinco"]'::jsonb, 3, 30, 'multiple_choice', NULL, NULL::jsonb);

